/**
 * MessageInput.js - Enterprise Chat Input Component
 *
 * Multi-modal input supporting:
 * - Text messages with emoji picker
 * - Voice recordings (WebM Opus, 30s max)
 * - Image attachments (with preview)
 * - Typing indicators (auto-managed)
 *
 * ENTERPRISE FEATURES:
 * - Debounced typing indicators (300ms)
 * - Auto-resize textarea (max 6 lines)
 * - Draft persistence (localStorage)
 * - Upload progress tracking
 * - Error handling with retry
 * - Accessibility (ARIA, keyboard)
 *
 * @package Need2Talk
 * @author Claude Code (AI-Orchestrated Development)
 * @since 2025-12-02
 * @version 1.0.0
 */

class MessageInput {
    static TYPING_DEBOUNCE = 300;       // ms
    static TYPING_STOP_DELAY = 3000;    // ms after last keystroke
    static MAX_TEXT_LENGTH = 4000;      // characters
    static MAX_AUDIO_DURATION = 30;     // seconds
    static MAX_IMAGE_SIZE = 5 * 1024 * 1024;  // 5MB
    static ALLOWED_IMAGE_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];

    #container = null;
    #config = {};
    #elements = {};
    #state = {
        isRecording: false,
        recordingStart: null,
        recordingTimer: null,
        typingTimeout: null,
        isTyping: false,
        pendingAttachment: null,
        mediaRecorder: null,
        audioChunks: [],
        uploading: false,
        isPausedAtLimit: false,  // ENTERPRISE V3.2: Track if paused at 30s limit
        pausedAt: null,          // ENTERPRISE V3.2: Track when paused for time adjustment
        isPendingPermission: false,  // ENTERPRISE V10.69: Prevent multiple recorders during permission prompt
    };
    #callbacks = {
        onSend: null,
        onTypingStart: null,
        onTypingStop: null,
        onError: null,
    };

    /**
     * Create MessageInput instance
     * @param {HTMLElement|string} container
     * @param {Object} config
     */
    constructor(container, config = {}) {
        this.#container = typeof container === 'string'
            ? document.querySelector(container)
            : container;

        if (!this.#container) {
            throw new Error('MessageInput: Container not found');
        }

        this.#config = {
            roomId: config.roomId || null,
            conversationId: config.conversationId || null,
            roomType: config.roomType || 'emotion',  // emotion, private, dm
            placeholder: config.placeholder || 'Scrivi un messaggio...',
            enableAudio: config.enableAudio !== false,
            enableImages: config.enableImages !== false,
            enableEmoji: config.enableEmoji !== false,
            maxTextLength: config.maxTextLength || MessageInput.MAX_TEXT_LENGTH,
            draftKey: config.draftKey || null,
            ...config,
        };

        this.#init();
    }

    // ========================================================================
    // INITIALIZATION
    // ========================================================================

    #init() {
        this.#render();
        this.#bindEvents();
        this.#loadDraft();
        this.#checkMediaSupport();
    }

    #render() {
        this.#container.innerHTML = `
            <div class="n2t-message-input" role="form" aria-label="Messaggio">
                <!-- Attachment Preview -->
                <div class="n2t-input-attachment-preview" style="display: none;">
                    <div class="n2t-attachment-content"></div>
                    <button type="button" class="n2t-attachment-remove" aria-label="Rimuovi allegato">
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                            <line x1="18" y1="6" x2="6" y2="18"></line>
                            <line x1="6" y1="6" x2="18" y2="18"></line>
                        </svg>
                    </button>
                </div>

                <!-- Recording UI -->
                <div class="n2t-input-recording" style="display: none;">
                    <button type="button" class="n2t-recording-cancel" aria-label="Annulla registrazione" title="Annulla">
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                            <line x1="18" y1="6" x2="6" y2="18"></line>
                            <line x1="6" y1="6" x2="18" y2="18"></line>
                        </svg>
                    </button>
                    <div class="n2t-recording-indicator">
                        <span class="n2t-recording-dot"></span>
                        <span class="n2t-recording-time">0:00</span>
                    </div>
                    <button type="button" class="n2t-recording-pause" aria-label="Pausa registrazione" title="Pausa">
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                            <rect x="6" y="4" width="4" height="16"></rect>
                            <rect x="14" y="4" width="4" height="16"></rect>
                        </svg>
                    </button>
                    <button type="button" class="n2t-recording-send" aria-label="Invia registrazione" title="Invia">
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                            <polyline points="20 6 9 17 4 12"></polyline>
                        </svg>
                    </button>
                </div>

                <!-- Main Input Area -->
                <div class="n2t-input-main">
                    <!-- Action Buttons (Left) -->
                    <div class="n2t-input-actions-left">
                        ${this.#config.enableImages ? `
                            <button type="button" class="n2t-input-btn n2t-btn-attach" aria-label="Allega immagine" title="Allega immagine">
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                                    <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                                    <circle cx="8.5" cy="8.5" r="1.5"></circle>
                                    <polyline points="21 15 16 10 5 21"></polyline>
                                </svg>
                            </button>
                            <input type="file" class="n2t-input-file" accept="image/*" style="display: none;">
                        ` : ''}
                        ${this.#config.enableEmoji ? `
                            <button type="button" class="n2t-input-btn n2t-btn-emoji" aria-label="Inserisci emoji" title="Emoji">
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                                    <circle cx="12" cy="12" r="10"></circle>
                                    <path d="M8 14s1.5 2 4 2 4-2 4-2"></path>
                                    <line x1="9" y1="9" x2="9.01" y2="9"></line>
                                    <line x1="15" y1="9" x2="15.01" y2="9"></line>
                                </svg>
                            </button>
                        ` : ''}
                    </div>

                    <!-- Text Input -->
                    <div class="n2t-input-text-wrapper">
                        <textarea
                            class="n2t-input-textarea"
                            placeholder="${this.#escapeHtml(this.#config.placeholder)}"
                            maxlength="${this.#config.maxTextLength}"
                            rows="1"
                            aria-label="Scrivi messaggio"
                        ></textarea>
                        <div class="n2t-input-char-count" style="display: none;">
                            <span class="n2t-char-current">0</span>/<span class="n2t-char-max">${this.#config.maxTextLength}</span>
                        </div>
                    </div>

                    <!-- Action Buttons (Right) -->
                    <div class="n2t-input-actions-right">
                        ${this.#config.enableAudio ? `
                            <button type="button" class="n2t-input-btn n2t-btn-voice" aria-label="Registra audio" title="Registra messaggio vocale">
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                                    <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path>
                                    <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
                                    <line x1="12" y1="19" x2="12" y2="23"></line>
                                    <line x1="8" y1="23" x2="16" y2="23"></line>
                                </svg>
                            </button>
                        ` : ''}
                        <button type="button" class="n2t-input-btn n2t-btn-send" aria-label="Invia messaggio" title="Invia" disabled>
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                                <line x1="22" y1="2" x2="11" y2="13"></line>
                                <polygon points="22 2 15 22 11 13 2 9 22 2"></polygon>
                            </svg>
                        </button>
                    </div>
                </div>

                <!-- Upload Progress -->
                <div class="n2t-input-upload-progress" style="display: none;">
                    <div class="n2t-upload-bar">
                        <div class="n2t-upload-fill" style="width: 0%"></div>
                    </div>
                    <span class="n2t-upload-text">Caricamento...</span>
                </div>

                <!-- Emoji Picker (lazy loaded) -->
                <div class="n2t-emoji-picker" style="display: none;"></div>
            </div>
        `;

        // Cache element references
        this.#elements = {
            root: this.#container.querySelector('.n2t-message-input'),
            textarea: this.#container.querySelector('.n2t-input-textarea'),
            sendBtn: this.#container.querySelector('.n2t-btn-send'),
            voiceBtn: this.#container.querySelector('.n2t-btn-voice'),
            attachBtn: this.#container.querySelector('.n2t-btn-attach'),
            emojiBtn: this.#container.querySelector('.n2t-btn-emoji'),
            fileInput: this.#container.querySelector('.n2t-input-file'),
            charCount: this.#container.querySelector('.n2t-input-char-count'),
            charCurrent: this.#container.querySelector('.n2t-char-current'),
            attachmentPreview: this.#container.querySelector('.n2t-input-attachment-preview'),
            attachmentContent: this.#container.querySelector('.n2t-attachment-content'),
            attachmentRemove: this.#container.querySelector('.n2t-attachment-remove'),
            recordingUI: this.#container.querySelector('.n2t-input-recording'),
            recordingTime: this.#container.querySelector('.n2t-recording-time'),
            recordingCancel: this.#container.querySelector('.n2t-recording-cancel'),
            recordingPause: this.#container.querySelector('.n2t-recording-pause'),
            recordingSend: this.#container.querySelector('.n2t-recording-send'),
            recordingDot: this.#container.querySelector('.n2t-recording-dot'),
            uploadProgress: this.#container.querySelector('.n2t-input-upload-progress'),
            uploadFill: this.#container.querySelector('.n2t-upload-fill'),
            uploadText: this.#container.querySelector('.n2t-upload-text'),
            emojiPicker: this.#container.querySelector('.n2t-emoji-picker'),
            mainArea: this.#container.querySelector('.n2t-input-main'),
        };
    }

    #bindEvents() {
        // Textarea events
        this.#elements.textarea.addEventListener('input', this.#handleInput.bind(this));
        this.#elements.textarea.addEventListener('keydown', this.#handleKeydown.bind(this));
        this.#elements.textarea.addEventListener('paste', this.#handlePaste.bind(this));
        this.#elements.textarea.addEventListener('focus', () => {
            this.#elements.root.classList.add('focused');
            // ENTERPRISE V10.78: Trigger read receipt when user focuses input
            // This marks incoming messages as read immediately when user clicks on the chat
            this.#triggerReadReceipt();
        });
        this.#elements.textarea.addEventListener('blur', () => this.#elements.root.classList.remove('focused'));

        // Send button
        this.#elements.sendBtn.addEventListener('click', this.#handleSend.bind(this));

        // Voice recording
        if (this.#elements.voiceBtn) {
            this.#elements.voiceBtn.addEventListener('click', this.#handleVoiceClick.bind(this));
            this.#elements.recordingCancel.addEventListener('click', this.#cancelRecording.bind(this));
            this.#elements.recordingPause.addEventListener('click', this.#togglePauseRecording.bind(this));
            this.#elements.recordingSend.addEventListener('click', this.#sendRecording.bind(this));
        }

        // Image attachment
        if (this.#elements.attachBtn) {
            this.#elements.attachBtn.addEventListener('click', () => this.#elements.fileInput.click());
            this.#elements.fileInput.addEventListener('change', this.#handleFileSelect.bind(this));
            this.#elements.attachmentRemove.addEventListener('click', this.#removeAttachment.bind(this));
        }

        // Emoji picker
        if (this.#elements.emojiBtn) {
            this.#elements.emojiBtn.addEventListener('click', this.#toggleEmojiPicker.bind(this));
        }

        // Click outside to close emoji picker
        // ENTERPRISE FIX: Use closest() to handle clicks on SVG children inside button
        document.addEventListener('click', (e) => {
            if (this.#elements.emojiPicker.style.display !== 'none' &&
                !this.#elements.emojiPicker.contains(e.target) &&
                !e.target.closest('.n2t-btn-emoji')) {
                this.#elements.emojiPicker.style.display = 'none';
            }
        });
    }

    // ========================================================================
    // INPUT HANDLING
    // ========================================================================

    #handleInput(e) {
        const text = e.target.value;
        const length = text.length;

        // Auto-resize textarea
        this.#autoResize();

        // Update character count
        if (length > this.#config.maxTextLength * 0.8) {
            this.#elements.charCount.style.display = 'block';
            this.#elements.charCurrent.textContent = length;

            if (length >= this.#config.maxTextLength) {
                this.#elements.charCount.classList.add('limit-reached');
            } else {
                this.#elements.charCount.classList.remove('limit-reached');
            }
        } else {
            this.#elements.charCount.style.display = 'none';
        }

        // Update send button state
        this.#updateSendButton();

        // Handle typing indicator
        this.#handleTyping();

        // Save draft
        this.#saveDraft();
    }

    #autoResize() {
        const textarea = this.#elements.textarea;
        textarea.style.height = 'auto';
        const maxHeight = parseInt(getComputedStyle(textarea).lineHeight) * 6;  // 6 lines max
        textarea.style.height = Math.min(textarea.scrollHeight, maxHeight) + 'px';
    }

    #handleKeydown(e) {
        // Enter to send (without shift)
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            if (this.#canSend()) {
                this.#handleSend();
            }
        }
    }

    #handlePaste(e) {
        // Handle image paste
        const items = e.clipboardData?.items;
        if (!items) return;

        for (const item of items) {
            if (item.type.startsWith('image/')) {
                e.preventDefault();
                const file = item.getAsFile();
                if (file) {
                    this.#processImageFile(file);
                }
                return;
            }
        }
    }

    #handleTyping() {
        // Debounced typing indicator
        if (!this.#state.isTyping) {
            this.#state.isTyping = true;
            this.#callbacks.onTypingStart?.();

            // ENTERPRISE V10.78: Trigger read receipt on first keystroke
            // When user starts typing, they're actively engaging with the chat
            // This marks incoming messages as "read" immediately
            this.#triggerReadReceipt();
        }

        // Reset stop timer
        if (this.#state.typingTimeout) {
            clearTimeout(this.#state.typingTimeout);
        }

        this.#state.typingTimeout = setTimeout(() => {
            this.#state.isTyping = false;
            this.#callbacks.onTypingStop?.();
        }, MessageInput.TYPING_STOP_DELAY);
    }

    /**
     * ENTERPRISE V10.78: Trigger read receipt when user engages with chat
     * Called on first keystroke to mark incoming messages as read
     * Uses ReadReceiptManager for visibility-aware receipts
     */
    #triggerReadReceipt() {
        const conversationId = this.#config.conversationId;
        if (!conversationId) return;

        // Use ReadReceiptManager if available (enterprise path)
        if (window.readReceiptManager) {
            window.readReceiptManager.onConversationOpened(conversationId, true);
        } else {
            // Fallback: Direct API call (only if visible and focused)
            if (document.hasFocus() && document.visibilityState === 'visible') {
                fetch(`/api/chat/dm/${conversationId}/read`, {
                    method: 'POST',
                    credentials: 'include'
                }).catch(() => {}); // Non-critical, ignore errors
            }
        }
    }

    // ========================================================================
    // SEND HANDLING
    // ========================================================================

    #updateSendButton() {
        const hasText = this.#elements.textarea.value.trim().length > 0;
        const hasAttachment = this.#state.pendingAttachment !== null;

        this.#elements.sendBtn.disabled = !hasText && !hasAttachment;

        // Toggle between voice and send button visibility
        if (this.#elements.voiceBtn) {
            if (hasText || hasAttachment) {
                this.#elements.voiceBtn.style.display = 'none';
                this.#elements.sendBtn.style.display = 'flex';
            } else {
                this.#elements.voiceBtn.style.display = 'flex';
                this.#elements.sendBtn.style.display = 'none';
            }
        }
    }

    #canSend() {
        const hasText = this.#elements.textarea.value.trim().length > 0;
        const hasAttachment = this.#state.pendingAttachment !== null;
        return (hasText || hasAttachment) && !this.#state.uploading;
    }

    async #handleSend() {
        if (!this.#canSend()) return;

        // Stop typing indicator
        if (this.#state.typingTimeout) {
            clearTimeout(this.#state.typingTimeout);
        }
        if (this.#state.isTyping) {
            this.#state.isTyping = false;
            this.#callbacks.onTypingStop?.();
        }

        const text = this.#elements.textarea.value.trim();
        const attachment = this.#state.pendingAttachment;

        // Build message payload
        const message = {
            type: attachment ? attachment.type : 'text',
            content: text || null,
        };

        // Handle attachment upload first
        if (attachment) {
            this.#showUploadProgress();
            try {
                const uploadResult = await this.#uploadAttachment(attachment);
                message.attachment = uploadResult;
            } catch (error) {
                this.#hideUploadProgress();
                this.#callbacks.onError?.('Errore caricamento file: ' + error.message);
                return;
            }
            this.#hideUploadProgress();
        }

        // Clear input
        this.#elements.textarea.value = '';
        this.#autoResize();
        this.#removeAttachment();
        this.#clearDraft();
        this.#updateSendButton();

        // Invoke callback
        try {
            await this.#callbacks.onSend?.(message);
        } catch (error) {
            this.#callbacks.onError?.('Errore invio messaggio: ' + error.message);
        }
    }

    // ========================================================================
    // VOICE RECORDING
    // ========================================================================

    #checkMediaSupport() {
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
            if (this.#elements.voiceBtn) {
                this.#elements.voiceBtn.disabled = true;
                this.#elements.voiceBtn.title = 'Registrazione non supportata su questo browser';
            }
        }
    }

    async #handleVoiceClick() {
        // Prevent multiple recorders during permission prompt
        if (this.#state.isPendingPermission) return;

        if (this.#state.isRecording) {
            // Already recording - stop and send
            this.#sendRecording();
        } else {
            // Start recording
            await this.#startRecording();
        }
    }

    async #startRecording() {
        // ENTERPRISE V10.69: Set pending flag BEFORE async getUserMedia
        // This prevents multiple recorders if user clicks while permission dialog is open
        this.#state.isPendingPermission = true;

        try {
            // ENTERPRISE V11.8: noiseSuppression disabled - too aggressive on some devices
            // Users reported "even shouting only gets fragments of words" when enabled
            const stream = await navigator.mediaDevices.getUserMedia({
                audio: {
                    channelCount: 1,
                    sampleRate: 16000,
                    echoCancellation: true,
                    noiseSuppression: false,  // DISABLED: Too aggressive, cuts speech
                },
            });

            // Check for WebM Opus support
            const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
                ? 'audio/webm;codecs=opus'
                : 'audio/webm';

            this.#state.mediaRecorder = new MediaRecorder(stream, {
                mimeType,
                audioBitsPerSecond: 48000,
            });

            this.#state.audioChunks = [];

            this.#state.mediaRecorder.ondataavailable = (e) => {
                if (e.data.size > 0) {
                    this.#state.audioChunks.push(e.data);
                }
            };

            this.#state.mediaRecorder.onstop = () => {
                stream.getTracks().forEach(track => track.stop());
            };

            this.#state.mediaRecorder.start(100);  // 100ms chunks

            this.#state.isRecording = true;
            this.#state.isPendingPermission = false;  // ENTERPRISE V10.69: Permission granted, clear pending flag
            this.#state.recordingStart = Date.now();

            // Show recording UI
            this.#elements.mainArea.style.display = 'none';
            this.#elements.recordingUI.style.display = 'flex';

            // Start timer
            this.#updateRecordingTime();
            this.#state.recordingTimer = setInterval(() => {
                this.#updateRecordingTime();
            }, 100);

        } catch (error) {
            console.error('[MessageInput] Recording error:', error);

            // ENTERPRISE V10.69: Clear pending flag on error (permission denied, etc.)
            this.#state.isPendingPermission = false;

            if (error.name === 'NotAllowedError') {
                this.#callbacks.onError?.('Permesso microfono negato. Abilita il microfono per registrare.');
            } else {
                this.#callbacks.onError?.('Impossibile avviare registrazione: ' + error.message);
            }
        }
    }

    #updateRecordingTime() {
        const elapsed = (Date.now() - this.#state.recordingStart) / 1000;
        const minutes = Math.floor(elapsed / 60);
        const seconds = Math.floor(elapsed % 60);

        this.#elements.recordingTime.textContent =
            `${minutes}:${seconds.toString().padStart(2, '0')}`;

        // ENTERPRISE V3.2: Auto-PAUSE at max duration (30s) instead of auto-send
        // Recording stops but waits for user to confirm send or cancel
        if (elapsed >= MessageInput.MAX_AUDIO_DURATION && this.#state.mediaRecorder?.state === 'recording') {
            this.#state.mediaRecorder.pause();
            this.#state.isPausedAtLimit = true;
            this.#state.pausedAt = Date.now();  // ENTERPRISE FIX: Track pause time for duration calculation

            // Update UI to show limit reached
            this.#elements.recordingTime.textContent = '0:30 MAX';
            this.#elements.recordingTime.style.color = '#fbbf24';

            // Stop timer updates
            if (this.#state.recordingTimer) {
                clearInterval(this.#state.recordingTimer);
                this.#state.recordingTimer = null;
            }

            // Add visual indicator to dot
            if (this.#elements.recordingDot) {
                this.#elements.recordingDot.classList.add('paused');
            }

            // ENTERPRISE V3.3: Pulse animation on send button to notify user
            if (this.#elements.recordingSend) {
                this.#elements.recordingSend.classList.add('n2t-pulse-attention');
                // Brief vibration if supported (mobile)
                if (navigator.vibrate) navigator.vibrate(100);
            }

            // Disable pause button (can't resume past 30s)
            if (this.#elements.recordingPause) {
                this.#elements.recordingPause.disabled = true;
                this.#elements.recordingPause.style.opacity = '0.5';
                this.#elements.recordingPause.innerHTML = `
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                        <path d="M8 5v14l11-7z"></path>
                    </svg>
                `;
            }
        }

        // Update progress bar (visual feedback)
        const progress = Math.min((elapsed / MessageInput.MAX_AUDIO_DURATION) * 100, 100);
        this.#elements.recordingUI.style.setProperty('--recording-progress', progress + '%');
    }

    /**
     * ENTERPRISE V3.2: Toggle pause/resume recording
     */
    #togglePauseRecording() {
        if (!this.#state.mediaRecorder || !this.#state.isRecording) return;

        // Can't resume if already at 30s limit
        if (this.#state.isPausedAtLimit) return;

        const pauseBtn = this.#elements.recordingPause;
        const dot = this.#elements.recordingDot;

        if (this.#state.mediaRecorder.state === 'recording') {
            // Pause
            this.#state.mediaRecorder.pause();
            this.#state.pausedAt = Date.now();

            // Update button to show play icon
            pauseBtn.innerHTML = `
                <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M8 5v14l11-7z"></path>
                </svg>
            `;
            pauseBtn.title = 'Riprendi';
            pauseBtn.setAttribute('aria-label', 'Riprendi registrazione');

            // Add paused class to dot
            if (dot) dot.classList.add('paused');

        } else if (this.#state.mediaRecorder.state === 'paused') {
            // Resume - adjust start time to account for pause duration
            const pauseDuration = Date.now() - this.#state.pausedAt;
            this.#state.recordingStart += pauseDuration;
            this.#state.mediaRecorder.resume();

            // Update button to show pause icon
            pauseBtn.innerHTML = `
                <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                    <rect x="6" y="4" width="4" height="16"></rect>
                    <rect x="14" y="4" width="4" height="16"></rect>
                </svg>
            `;
            pauseBtn.title = 'Pausa';
            pauseBtn.setAttribute('aria-label', 'Pausa registrazione');

            // Remove paused class from dot
            if (dot) dot.classList.remove('paused');
        }
    }

    #cancelRecording() {
        if (this.#state.mediaRecorder && this.#state.isRecording) {
            this.#state.mediaRecorder.stop();
        }

        this.#resetRecordingState();
    }

    async #sendRecording() {
        if (!this.#state.mediaRecorder || !this.#state.isRecording) return;

        // Stop recording (works for both 'recording' and 'paused' states)
        if (this.#state.mediaRecorder.state !== 'inactive') {
            this.#state.mediaRecorder.stop();
        }

        // Wait for all data
        await new Promise(resolve => {
            this.#state.mediaRecorder.onstop = resolve;
        });

        // Create blob
        const audioBlob = new Blob(this.#state.audioChunks, { type: 'audio/webm' });

        // ENTERPRISE FIX: Calculate duration correctly when paused at 30s limit
        // If recording was auto-paused at limit, duration is exactly 30s (or pausedAt - start)
        // Otherwise, calculate from current time accounting for any pauses
        let duration;
        if (this.#state.isPausedAtLimit && this.#state.pausedAt) {
            // Auto-paused at 30s limit - use the pause timestamp
            duration = (this.#state.pausedAt - this.#state.recordingStart) / 1000;
            // Cap at MAX to handle any timing edge cases
            duration = Math.min(duration, MessageInput.MAX_AUDIO_DURATION);
        } else {
            duration = (Date.now() - this.#state.recordingStart) / 1000;
        }

        // Reset UI first
        this.#resetRecordingState();

        // Minimum duration check
        if (duration < 0.5) {
            this.#callbacks.onError?.('Registrazione troppo breve');
            return;
        }

        // Upload and send
        this.#showUploadProgress();
        try {
            // ENTERPRISE V10.100 (2025-12-09): TRUE E2E Encryption for DM Audio
            // Uses ChatEncryptionService with ECDH key exchange
            // Private key NEVER leaves browser - server cannot decrypt
            // NO FALLBACK: If encryption fails, audio is NOT sent
            let blobToUpload = audioBlob;
            let encryptionIv = null;
            let encryptionTag = null;

            try {
                // ENTERPRISE V10.179: Use awaitable singleton promise for proper initialization
                const chatEncryption = await window.chatEncryptionReady;
                if (!chatEncryption || !chatEncryption.isInitialized) {
                    throw new Error('ChatEncryptionService initialization failed');
                }

                if (!this.#config.conversationId) {
                    throw new Error('Conversation ID required for E2E encryption');
                }

                this.#updateUploadProgress(10, 'Crittografia E2E...');

                // TRUE E2E: Encrypt with ECDH-derived conversation key
                const result = await chatEncryption.encryptFile(audioBlob, this.#config.conversationId);

                if (!result || !result.encryptedBlob || !result.iv || !result.tag) {
                    throw new Error('Encryption returned incomplete result');
                }

                blobToUpload = result.encryptedBlob;
                encryptionIv = result.iv;
                encryptionTag = result.tag;
            } catch (encryptError) {
                console.error('[MessageInput] E2E encryption failed:', encryptError);
                throw new Error('Crittografia E2E fallita: ' + encryptError.message);
            }

            const uploadResult = await this.#uploadAudio(blobToUpload, duration, encryptionIv, encryptionTag);

            await this.#callbacks.onSend?.({
                type: 'audio',
                content: null,
                attachment: uploadResult,
            });
        } catch (error) {
            this.#callbacks.onError?.('Errore invio audio: ' + error.message);
        } finally {
            this.#hideUploadProgress();
        }
    }

    #resetRecordingState() {
        if (this.#state.recordingTimer) {
            clearInterval(this.#state.recordingTimer);
            this.#state.recordingTimer = null;
        }

        this.#state.isRecording = false;
        this.#state.recordingStart = null;
        this.#state.audioChunks = [];
        this.#state.mediaRecorder = null;
        this.#state.isPausedAtLimit = false;  // ENTERPRISE V3.2
        this.#state.pausedAt = null;          // ENTERPRISE V3.2

        // Restore UI
        this.#elements.recordingUI.style.display = 'none';
        this.#elements.mainArea.style.display = 'flex';

        // Reset recording time color
        if (this.#elements.recordingTime) {
            this.#elements.recordingTime.style.color = '';
        }

        // Reset pause button to default state
        if (this.#elements.recordingPause) {
            this.#elements.recordingPause.innerHTML = `
                <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                    <rect x="6" y="4" width="4" height="16"></rect>
                    <rect x="14" y="4" width="4" height="16"></rect>
                </svg>
            `;
            this.#elements.recordingPause.title = 'Pausa';
            this.#elements.recordingPause.disabled = false;
            this.#elements.recordingPause.style.opacity = '';
        }

        // Reset dot
        if (this.#elements.recordingDot) {
            this.#elements.recordingDot.classList.remove('paused');
        }
    }

    // ========================================================================
    // IMAGE ATTACHMENT
    // ========================================================================

    #handleFileSelect(e) {
        const file = e.target.files?.[0];
        if (!file) return;

        // Reset input for re-selection
        e.target.value = '';

        this.#processImageFile(file);
    }

    #processImageFile(file) {
        // Validate type
        if (!MessageInput.ALLOWED_IMAGE_TYPES.includes(file.type)) {
            this.#callbacks.onError?.('Tipo file non supportato. Usa JPEG, PNG, GIF o WebP.');
            return;
        }

        // Validate size
        if (file.size > MessageInput.MAX_IMAGE_SIZE) {
            this.#callbacks.onError?.('Immagine troppo grande. Max 5MB.');
            return;
        }

        // Create preview
        const reader = new FileReader();
        reader.onload = (e) => {
            this.#state.pendingAttachment = {
                type: 'image',
                file: file,
                preview: e.target.result,
            };

            this.#showAttachmentPreview();
            this.#updateSendButton();
        };
        reader.readAsDataURL(file);
    }

    #showAttachmentPreview() {
        const attachment = this.#state.pendingAttachment;
        if (!attachment) return;

        if (attachment.type === 'image') {
            this.#elements.attachmentContent.innerHTML = `
                <img src="${attachment.preview}" alt="Anteprima immagine" class="n2t-attachment-image-preview">
            `;
        }

        this.#elements.attachmentPreview.style.display = 'flex';
    }

    #removeAttachment() {
        this.#state.pendingAttachment = null;
        this.#elements.attachmentPreview.style.display = 'none';
        this.#elements.attachmentContent.innerHTML = '';
        this.#updateSendButton();
    }

    // ========================================================================
    // UPLOAD HANDLING
    // ========================================================================

    #showUploadProgress() {
        this.#state.uploading = true;
        this.#elements.uploadProgress.style.display = 'flex';
        this.#elements.sendBtn.disabled = true;
    }

    #hideUploadProgress() {
        this.#state.uploading = false;
        this.#elements.uploadProgress.style.display = 'none';
        this.#elements.uploadFill.style.width = '0%';
        this.#updateSendButton();
    }

    #updateUploadProgress(percent, text = null) {
        this.#elements.uploadFill.style.width = percent + '%';
        if (text) {
            this.#elements.uploadText.textContent = text;
        }
    }

    async #uploadAttachment(attachment) {
        const formData = new FormData();
        formData.append('file', attachment.file);

        if (this.#config.roomId) {
            formData.append('room_id', this.#config.roomId);
        } else if (this.#config.conversationId) {
            formData.append('conversation_id', this.#config.conversationId);
        }

        return this.#uploadWithProgress('/api/chat/upload/image', formData);
    }

    async #uploadAudio(blob, duration, encryptionIv = null, encryptionTag = null) {
        const formData = new FormData();
        formData.append('audio', blob, 'recording.webm');
        formData.append('duration', duration.toString());

        // ENTERPRISE V10.100 (2025-12-09): TRUE E2E encryption metadata
        // Server stores IV and TAG with the audio for decryption by recipient
        // Server CANNOT decrypt - only recipient with ECDH-derived key can
        if (encryptionIv && encryptionTag) {
            formData.append('is_encrypted', '1');
            formData.append('encryption_iv', encryptionIv);
            formData.append('encryption_tag', encryptionTag);
            formData.append('encryption_algorithm', 'AES-256-GCM');
        }

        // ENTERPRISE V3.1: Use correct endpoint for DM vs Room audio
        let uploadUrl;
        if (this.#config.conversationId) {
            // DM audio uses dedicated endpoint
            uploadUrl = `/api/chat/dm/${this.#config.conversationId}/audio`;
        } else if (this.#config.roomId) {
            // Room audio uses generic upload
            formData.append('room_id', this.#config.roomId);
            uploadUrl = '/api/chat/upload/audio';
        } else {
            throw new Error('No room or conversation ID configured');
        }

        return this.#uploadWithProgress(uploadUrl, formData);
    }

    async #uploadWithProgress(url, formData) {
        return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable) {
                    const percent = Math.round((e.loaded / e.total) * 100);
                    this.#updateUploadProgress(percent, `Caricamento ${percent}%`);
                }
            });

            xhr.addEventListener('load', () => {
                // ENTERPRISE V4.3: Accept both 200 OK (sync) and 202 Accepted (async worker)
                if (xhr.status >= 200 && xhr.status < 300) {
                    try {
                        const response = JSON.parse(xhr.responseText);
                        if (response.success) {
                            // Handle async worker response (202 Accepted)
                            if (response.data?.status === 'queued') {
                                // Return queued status - WebSocket event will update with final message
                                resolve({
                                    ...response.data,
                                    isAsync: true,
                                    pendingUpload: true
                                });
                            } else {
                                // Sync response (old flow or non-DM audio)
                                resolve(response.data);
                            }
                        } else {
                            reject(new Error(response.error || 'Upload failed'));
                        }
                    } catch {
                        reject(new Error('Invalid server response'));
                    }
                } else {
                    reject(new Error(`HTTP ${xhr.status}`));
                }
            });

            xhr.addEventListener('error', () => {
                reject(new Error('Network error'));
            });

            xhr.open('POST', url);
            xhr.withCredentials = true; // ENTERPRISE: Send session cookies
            xhr.setRequestHeader('X-CSRF-Token', window.Need2Talk?.CSRF?.getToken() || document.querySelector('meta[name="csrf-token"]')?.getAttribute('content') || '');
            xhr.send(formData);
        });
    }

    // ========================================================================
    // EMOJI PICKER (with MSN Emoticons for Chat Rooms)
    // ========================================================================

    #toggleEmojiPicker() {
        const picker = this.#elements.emojiPicker;

        if (picker.style.display === 'none') {
            this.#loadEmojiPicker();
            picker.style.display = 'block';
        } else {
            picker.style.display = 'none';
        }
    }

    #loadEmojiPicker() {
        if (this.#elements.emojiPicker.dataset.loaded) return;

        // Common emojis for chat
        const emojis = [
            '😊', '😂', '🥹', '😍', '🥰', '😘', '😎', '🤔',
            '😢', '😭', '😤', '😡', '🤯', '😱', '🤗', '🤭',
            '👍', '👎', '❤️', '💔', '🔥', '✨', '🎉', '👏',
            '🙏', '💪', '🤝', '👋', '✌️', '🤞', '🫶', '💕',
        ];

        // ENTERPRISE V11.9: Check if animated emoticons available (chat rooms only)
        const hasAnimatedEmoticons = this.#config.roomType !== 'dm' && window.AnimatedEmoticonData;

        this.#elements.emojiPicker.innerHTML = `
            <div class="n2t-emoji-picker-container">
                ${hasAnimatedEmoticons ? `
                    <!-- Tab Toggle -->
                    <div class="n2t-emoji-tabs">
                        <button type="button" class="n2t-emoji-tab active" data-tab="emoji">
                            😊 Emoji
                        </button>
                        <button type="button" class="n2t-emoji-tab" data-tab="emoticon">
                            🎭 MSN
                        </button>
                    </div>
                ` : ''}

                <!-- Emoji Tab -->
                <div class="n2t-emoji-tab-content" data-tab="emoji">
                    <div class="n2t-emoji-grid">
                        ${emojis.map(emoji => `
                            <button type="button" class="n2t-emoji-btn" data-emoji="${emoji}">
                                ${emoji}
                            </button>
                        `).join('')}
                    </div>
                </div>

                ${hasAnimatedEmoticons ? `
                    <!-- Animated Emoticons Tab (MSN Style) -->
                    <div class="n2t-emoji-tab-content hidden" data-tab="emoticon">
                        <div class="n2t-emoticon-picker">
                            ${window.AnimatedEmoticonData.generatePickerHTML()}
                        </div>
                    </div>
                ` : ''}
            </div>
        `;

        // Tab switching
        if (hasAnimatedEmoticons) {
            const tabs = this.#elements.emojiPicker.querySelectorAll('.n2t-emoji-tab');
            const contents = this.#elements.emojiPicker.querySelectorAll('.n2t-emoji-tab-content');

            tabs.forEach(tab => {
                tab.addEventListener('click', () => {
                    const tabName = tab.dataset.tab;
                    tabs.forEach(t => t.classList.toggle('active', t.dataset.tab === tabName));
                    contents.forEach(c => c.classList.toggle('hidden', c.dataset.tab !== tabName));
                });
            });

            // Initialize emoticon picker events
            const emoticonPicker = this.#elements.emojiPicker.querySelector('.n2t-emoticon-picker');
            if (emoticonPicker && window.AnimatedEmoticonData) {
                window.AnimatedEmoticonData.initPickerEvents(emoticonPicker, (shortcode) => {
                    this.#insertEmoji(shortcode + ' ');  // Add space after shortcode
                    this.#elements.emojiPicker.style.display = 'none';
                });
            }
        }

        // Emoji button clicks
        this.#elements.emojiPicker.addEventListener('click', (e) => {
            const btn = e.target.closest('.n2t-emoji-btn');
            if (btn) {
                this.#insertEmoji(btn.dataset.emoji);
                this.#elements.emojiPicker.style.display = 'none';
            }
        });

        this.#elements.emojiPicker.dataset.loaded = 'true';
    }

    #insertEmoji(emoji) {
        const textarea = this.#elements.textarea;
        const start = textarea.selectionStart;
        const end = textarea.selectionEnd;
        const text = textarea.value;

        textarea.value = text.substring(0, start) + emoji + text.substring(end);
        textarea.selectionStart = textarea.selectionEnd = start + emoji.length;
        textarea.focus();

        this.#handleInput({ target: textarea });
    }

    // ========================================================================
    // DRAFT PERSISTENCE
    // ========================================================================

    #getDraftKey() {
        if (this.#config.draftKey) return this.#config.draftKey;

        if (this.#config.roomId) {
            return `chat_draft_room_${this.#config.roomId}`;
        } else if (this.#config.conversationId) {
            return `chat_draft_dm_${this.#config.conversationId}`;
        }

        return null;
    }

    #loadDraft() {
        const key = this.#getDraftKey();
        if (!key) return;

        try {
            const draft = localStorage.getItem(key);
            if (draft) {
                this.#elements.textarea.value = draft;
                this.#autoResize();
                this.#updateSendButton();
            }
        } catch (e) {
            // LocalStorage not available
        }
    }

    #saveDraft() {
        const key = this.#getDraftKey();
        if (!key) return;

        try {
            const text = this.#elements.textarea.value;
            if (text) {
                localStorage.setItem(key, text);
            } else {
                localStorage.removeItem(key);
            }
        } catch (e) {
            // LocalStorage not available
        }
    }

    #clearDraft() {
        const key = this.#getDraftKey();
        if (!key) return;

        try {
            localStorage.removeItem(key);
        } catch (e) {
            // LocalStorage not available
        }
    }

    // ========================================================================
    // PUBLIC API
    // ========================================================================

    /**
     * Register event callbacks
     * @param {Object} callbacks
     */
    on(callbacks) {
        if (callbacks.send) this.#callbacks.onSend = callbacks.send;
        if (callbacks.typingStart) this.#callbacks.onTypingStart = callbacks.typingStart;
        if (callbacks.typingStop) this.#callbacks.onTypingStop = callbacks.typingStop;
        if (callbacks.error) this.#callbacks.onError = callbacks.error;
        return this;
    }

    /**
     * Focus the input
     */
    focus() {
        this.#elements.textarea.focus();
    }

    /**
     * Clear the input
     */
    clear() {
        this.#elements.textarea.value = '';
        this.#removeAttachment();
        this.#clearDraft();
        this.#autoResize();
        this.#updateSendButton();
    }

    /**
     * Disable/enable input
     * @param {boolean} disabled
     */
    setDisabled(disabled) {
        this.#elements.textarea.disabled = disabled;
        this.#elements.sendBtn.disabled = disabled;
        if (this.#elements.voiceBtn) this.#elements.voiceBtn.disabled = disabled;
        if (this.#elements.attachBtn) this.#elements.attachBtn.disabled = disabled;
        if (this.#elements.emojiBtn) this.#elements.emojiBtn.disabled = disabled;

        this.#elements.root.classList.toggle('disabled', disabled);
    }

    /**
     * Update room/conversation context
     * @param {Object} context
     */
    setContext(context) {
        this.#config.roomId = context.roomId || null;
        this.#config.conversationId = context.conversationId || null;
        this.#config.roomType = context.roomType || this.#config.roomType;

        // Load draft for new context
        this.#loadDraft();
    }

    /**
     * Get current input value
     * @returns {string}
     */
    getValue() {
        return this.#elements.textarea.value;
    }

    /**
     * Set input value
     * @param {string} value
     */
    setValue(value) {
        this.#elements.textarea.value = value;
        this.#autoResize();
        this.#updateSendButton();
    }

    /**
     * Destroy component
     */
    destroy() {
        if (this.#state.typingTimeout) clearTimeout(this.#state.typingTimeout);
        if (this.#state.recordingTimer) clearInterval(this.#state.recordingTimer);
        if (this.#state.mediaRecorder && this.#state.isRecording) {
            this.#state.mediaRecorder.stop();
        }

        this.#container.innerHTML = '';
    }

    // ========================================================================
    // UTILITIES
    // ========================================================================

    #escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

// Export
if (typeof module !== 'undefined' && module.exports) {
    module.exports = MessageInput;
}

window.MessageInput = MessageInput;

